[CmdletBinding()]
param([string]$Root=(Resolve-Path (Join-Path $PSScriptRoot '../..')).Path,[string]$OutputRoot=(Join-Path $Root 'artifacts/packages'),[switch]$AllowDirtySource)
$ErrorActionPreference='Stop';$manifest=Get-Content (Join-Path $Root 'scenarios/http2-websocket-performance/protocol-lab-package.json') -Raw|ConvertFrom-Json;if($manifest.packageVersion-ne'0.1.2'){throw 'HTTP/2 WebSocket scenario package version must be 0.1.2.'};& (Join-Path $Root 'scenarios/http2-websocket-performance/validate.ps1');& (Join-Path $PSScriptRoot 'Build-ProtocolLabComponentPackage.ps1') -ComponentPath 'scenarios/http2-websocket-performance' -Root $Root -OutputRoot $OutputRoot -AllowDirtySource:$AllowDirtySource
